class Solution {
public:
    int wordCount(vector<string>& startWords, vector<string>& targetWords) {
        unordered_map<int, int> startWordCount;
        for (const auto& word : startWords) {
            int mask = 0;
            for (char c : word) {
                mask |= 1 << (c - 'a');
            }
            startWordCount[mask]++;
        }

        int count = 0;
        for (const auto& word : targetWords) {
            int mask = 0;
            for (char c : word) {
                mask |= 1 << (c - 'a');
            }
            bool found = false;
            for (int i = mask; i >= 0; --i) {
                if ((i & mask) == i && startWordCount.find(i) != startWordCount.end()) {
                    int diff = mask ^ i;
                    if (__builtin_popcount(diff) == 1 || diff == 0) {
                        count++;
                        found = true;
                        break;
                    }
                }
            }
        }
        return count;
    }
};
